sql:
SELECT property_id
FROM properties
WHERE price > (SELECT AVG(price) FROM properties);

SELECT * 
FROM property_types 
WHERE type_id > 5;

SELECT property_id
FROM favorites
WHERE user_id = (SELECT user_id FROM users WHERE username = 'jane_smith');

SELECT COUNT(property_id) AS num_properties_above_avg_price
FROM properties
WHERE price > (SELECT AVG(price) FROM properties);

external_knowledge:
- "basking in the light of their open house period" metaphorically refers to properties that are currently in an open house timeframe; 
- "dawn of their open house has passed a certain time" means the start time of the open house is greater than a specified time;
- "dusk has not yet reached another" means the end time of the open house is less than a specified time.

sql:
SELECT properties.property_id, properties.address, properties.city, properties.state, properties.zip, properties.price
FROM properties
INNER JOIN open_houses ON properties.property_id = open_houses.property_id;

SELECT * 
FROM open_houses 
WHERE date = 'November-15-2017';

SELECT property_id 
FROM properties 
WHERE property_id NOT IN (SELECT property_id FROM favorites);

SELECT property_id, sale_type, address, city, state, zip, price, beds, baths, location, square_feet, lot_size, year_built, days_on_market, price_per_square_foot, hoa_month, status, latitude, longitude, source_id, last_updated, description, image_urls
FROM properties
WHERE property_id = 0;
